@skipUnlessDBFeature('supports_tablespaces')
def test_tablespaces(self):
    tests = [
        {
            "name": "indexed_field",
            "sql_calls": [(sql_for_table, Article)],
            "checks": [
                (settings.DEFAULT_INDEX_TABLESPACE, {
                    True: [("tbl_tbsp", 1), (settings.DEFAULT_INDEX_TABLESPACE, 2)],
                    False: [("tbl_tbsp", 3)],
                }),
                ("idx_tbsp", 1),
            ],
        },
        {
            "name": "many_to_many_field",
            "sql_calls": [
                (sql_for_table, Authors),
                (sql_for_index, Authors),
                (sql_for_table, Reviewers),
                (sql_for_index, Reviewers),
            ],
            "checks": [
                # For sql_for_table(Authors)
                (settings.DEFAULT_INDEX_TABLESPACE, {
                    True: [("tbl_tbsp", 1), (settings.DEFAULT_INDEX_TABLESPACE, 1)],
                    False: [("tbl_tbsp", 2)],
                }),
                ("idx_tbsp", 0),

                # For sql_for_index(Authors)
                (settings.DEFAULT_INDEX_TABLESPACE, {
                    True: [(settings.DEFAULT_INDEX_TABLESPACE, 2)],
                    False: [("tbl_tbsp", 2)],
                }),
                ("idx_tbsp", 0),

                # For sql_for_table(Reviewers)
                (settings.DEFAULT_INDEX_TABLESPACE, {
                    True: [("tbl_tbsp", 1), (settings.DEFAULT_INDEX_TABLESPACE, 1)],
                    False: [("tbl_tbsp", 2)],
                }),
                ("idx_tbsp", 0),

                # For sql_for_index(Reviewers)
                ("tbl_tbsp", 0),
                ("idx_tbsp", 2),
            ],
        },
    ]

    for test in tests:
        with self.subTest(test=test["name"]):
            sqls = []
            for func, model in test["sql_calls"]:
                sqls.append(func(model).lower())

            # Index to track which sql we are checking in many_to_many_field
            sql_index = 0
            for check in test["checks"]:
                if isinstance(check, tuple) and isinstance(check[1], dict):
                    # conditional checks based on DEFAULT_INDEX_TABLESPACE
                    cond = settings.DEFAULT_INDEX_TABLESPACE
                    for substr, count in check[1][cond]:
                        self.assertNumContains(sqls[sql_index], substr, count)
                    sql_index += 1
                else:
                    # simple checks, apply to current sql_index or last sql if only one sql call
                    substr, count = check
                    # For many_to_many_field, some checks apply to the last sql call
                    if test["name"] == "many_to_many_field":
                        # Determine which sql to check based on sql_index
                        # If sql_index < len(sqls), use sqls[sql_index], else last sql
                        idx = sql_index if sql_index < len(sqls) else len(sqls) - 1
                        self.assertNumContains(sqls[idx], substr, count)
                    else:
                        self.assertNumContains(sqls[0], substr, count)
